parameters.jsCode:
// Configuration - UPDATE THESE VALUES
const config = {
  CALENDAR_ID: "YOUR_CALENDAR_ID@group.calendar.google.com",
  YOUR_EMAIL: "your@email.com",
  BOOKINGS_SHEET_ID: "YOUR_BOOKINGS_LOG_SHEET_ID",
  BUSINESS_NAME: "BookEase Appointments",
  BUSINESS_PHONE: "+91-9876543210"
};

// Extract form data
const formData = $json;

return [{
  json: {
    config,
    booking: {
      timestamp: new Date().toISOString(),
      name: formData['Full Name'] || formData.Name,
      email: formData['Email Address'] || formData.Email,
      phone: formData['Phone Number'] || formData.Phone,
      service: formData['Select Service'] || formData.Service,
      preferredDate: formData['Preferred Appointment Date'] || formData.Date,
      preferredTime: formData['Preferred Time Slot'] || formData.Time,
      notes: formData['Any special requirements or notes?'] || formData.Notes || ''
    }
  }
}];

const { booking } = $json;

// Parse the date and time
const dateStr = booking.preferredDate;
const timeStr = booking.preferredTime;

// Extract time range (e.g., "9:00 AM - 10:00 AM")
const timeMatch = timeStr.match(/(\d{1,2}:\d{2}\s*(?:AM|PM))/);
if (!timeMatch) {
  throw new Error('Invalid time format');
}

const startTimeStr = timeMatch[1];

// Parse date
const dateParts = dateStr.split('/');
let appointmentDate;

if (dateParts.length === 3) {
  // Format: MM/DD/YYYY or DD/MM/YYYY
  const month = parseInt(dateParts[0]) - 1; // JS months are 0-indexed
  const day = parseInt(dateParts[1]);
  const year = parseInt(dateParts[2]);
  appointmentDate = new Date(year, month, day);
} else {
  // Try ISO format
  appointmentDate = new Date(dateStr);
}

// Parse time
const [time, period] = startTimeStr.split(/\s+/);
const [hours, minutes] = time.split(':').map(Number);

let hour24 = hours;
if (period === 'PM' && hours !== 12) hour24 += 12;
if (period === 'AM' && hours === 12) hour24 = 0;

appointmentDate.setHours(hour24, minutes, 0, 0);

// Calculate end time based on service
const serviceDurations = {
  'Consultation (30 min)': 30,
  'Full Session (60 min)': 60,
  'Follow-up (15 min)': 15,
  'Workshop (90 min)': 90
};

const duration = serviceDurations[booking.service] || 60;
const endDate = new Date(appointmentDate.getTime() + duration * 60000);

return [{
  json: {
    ...$json,
    appointment: {
      startDateTime: appointmentDate.toISOString(),
      endDateTime: endDate.toISOString(),
      duration,
      dateFormatted: appointmentDate.toLocaleDateString('en-IN', { 
        weekday: 'long', 
        year: 'numeric', 
        month: 'long', 
        day: 'numeric' 
      }),
      timeFormatted: appointmentDate.toLocaleTimeString('en-IN', { 
        hour: '2-digit', 
        minute: '2-digit',
        hour12: True
      })
    }
  }
}];

